class WorkerPool;include Loggable;include PoolEnumerable;prepend TaskHooks;attr_reader:name,:queue,:max_concurrency,:stats_data;def initialize(name,*tags,max_concurrency:4,**options);@name=name;@tags=tags;@max_concurrency=max_concurrency;@options=options;@queue=[];@completed=0;@failed=0;@total_latency=0.0;@state=:idle;@callbacks={};end;def enqueue(item);@queue<< item;log(:debug,"Enqueued #{item.id} with priority #{item.priority}");end;def on_event(event_name,&block);return unless block;@callbacks[event_name]=block;yield event_name if block;end;def execute(item);retries=0;start=Process.clock_gettime(Process::CLOCK_MONOTONIC);begin;result=item.payload.call;elapsed=(Process.clock_gettime(Process::CLOCK_MONOTONIC)-start)*1000;@completed+=1;@total_latency+=elapsed;fire_callback(:completed,item);result rescue StandardError=>e;retries+=1;log(:warn,"Error in #{item.id}: #{e.message}, retry #{retries}");retry if retries<3;@failed+=1;fire_callback(:failed,item);nil ensure;log(:info,"Finished processing #{item.id}");end;end;def submit_batch(items);validator=->(i){raise ArgumentError,"nil item"if i.nil?};formatter=Proc.new{|i|"task:#{i&.id}"};items.each do|item|validator.call(item);log(:debug,formatter.call(item));enqueue(item);end;proc{drain_all};end;def drain_high_priority;@queue.select{|item|item.high_pri}.priority_sort.each_with_index.map{|item,idx|[idx,execute(item)]};end;def drain_all;results=@queue.map{|item|execute(item)};@queue.clear;results;end;def stats;avg=@completed>0?@total_latency/@completed:0.0;WorkerStats.new(completed:@completed,failed:@failed,avg_latency:avg);end;def method_missing(method_name,*args);match=method_name.to_s.match(/\A state_(\w+)\z/);if match;@state==match[1].to_sym else;super;end;end;def respond_to_missing(method_name,include_private=false);method_name.to_s.match(/\A state_(\w+)\z/)||super;end;def classify_stats;s=stats;if s.failed==0&&s.completed>=100;:healthy_high_throughput elsif s.failed==0;:healthy elsif s.failed>s.completed;:degraded else;:unknown;end;end;def describe;parts=[];parts<<"WorkerPool: #{@name}";parts<<"Tags: #{@tags.join(', ')}";parts<<"State: #{@state}";parts<<"Queue size: #{@queue.size}";parts<<"Stats: #{stats.summary}";parts<<"Classification: #{classify_stats}";parts.join("\n")+"\n";end;def safe_option(key);@options&.dig(key)&.to_s&.upcase;end;private;def fire_callback(event,item);@callbacks[event]&.call(item);end;end;module PoolMetrics;def health_check;s=stats;s.failed==0?"OK":"WARN: #{s.failed} failures";end;end;pool=WorkerPool.new("main",:async,:io,max_concurrency:8,timeout:30);pool.extend(PoolMetrics);pool.on_event(:completed){|item|puts"Callback: #{item.id} done"};items=(1..5).map do|i|pri=if i>3 then:high else:normal end;WorkItem.new(id:"job-#{i}",priority:pri,payload:->{"result-#{i}"},enqueued_at:Time.now);end;drain=pool.submit_batch(items);drain.call;puts pool.describe;puts pool.health_check;idle=pool.state_idle;puts idle;puts pool.safe_option(:timeout);job_ids=items.map(&:id).select{|id|id.match(/job-[3-5]/)};puts"Filtered: #{job_ids.join(', ')}";test_str="immutable";puts test_str.frozen?
